#include <stdio.h>
#include <math.h>
#define MOD 1000000007
int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N, Q;
        scanf("%d %d", &N, &Q);
        long long A[N + 1];
        for (int i = 1; i <= N; i++) {
            scanf("%lld", &A[i]);
        }
        while (Q--) {
            long long x;
            scanf("%lld", &x);
            long long ans = 0;
            for (int i = 1; i <= N; i++) {
                ans = (ans + (long long)floor(pow(x, 1.0 / i)) * A[i]) % MOD;
            }
            printf("%lld ", ans);
        }
        printf("\n");
    }
    return 0;
}

