import java.util.Scanner;
public class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        while (T-- > 0) {
            int N = sc.nextInt();
            int Q = sc.nextInt();
            long[] A = new long[N + 1];
            for (int i = 1; i <= N; i++) {
                A[i] = sc.nextLong();
            }
            while (Q-- > 0) {
                long x = sc.nextLong();
                long ans = 0;
                for (int i = 1; i <= N; i++) {
                    ans = (ans + (long) Math.floor(Math.pow(x, 1.0 / i)) * A[i]) % 1000000007;
                }
                System.out.print(ans + " ");
            }
            System.out.println();
        }
    }
}

